# Core Insight

This skill critically examines the methodology of using LLMs as judges in evaluation tasks, addressing fundamental questions about reliability, consistency, and validity. Rather than treating LLM judgments as ground truth, this approach systematically probes potential biases, inconsistencies, and limitations in LLM-based evaluation. It provides frameworks for understanding when LLMs can reliably serve as evaluators and when alternative or supplementary approaches are needed, contributing to more rigorous AI evaluation standards.

# Implementation

```python
import json
import numpy as np
from typing import Dict, List, Tuple, Optional
from dataclasses import dataclass
from enum import Enum

class JudgmentType(Enum):
    """Types of judgments LLMs can make."""
    PREFERENCE = "preference"
    SCORING = "scoring"
    CLASSIFICATION = "classification"
    REASONING_QUALITY = "reasoning_quality"
    FACTUALITY = "factuality"
    COHERENCE = "coherence"

class ReliabilityLevel(Enum):
    """Assessment of judgment reliability."""
    HIGH = "high"
    MODERATE = "moderate"
    LOW = "low"
    UNRELIABLE = "unreliable"

@dataclass
class JudgmentInstance:
    """Single judgment made by an LLM."""
    judgment_id: str
    judgment_type: JudgmentType
    content_a: str
    content_b: Optional[str]
    judgment: str
    confidence: float
    reasoning: str
    judge_model: str

@dataclass
class ConsistencyAnalysis:
    """Analysis of judgment consistency."""
    agreement_rate: float
    pairwise_consistency: float
    temporal_consistency: float
    pattern_stability: float
    bias_indicators: Dict[str, float]

class WhenReasoningLaws:
    """Critical assessment of LLM-as-a-judge methodology."""

    def __init__(self):
        self.judgments = []
        self.consistency_analyses = []
        self.reliability_assessments = []
        self.methodology_critiques = []

    def evaluate_judge_reliability(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Evaluate reliability of LLM judgments."""
        if not judgment_set:
            return {'reliability': ReliabilityLevel.UNRELIABLE.value, 'scores': {}}

        consistency = self._assess_consistency(judgment_set)
        bias = self._assess_bias(judgment_set)
        stability = self._assess_judgment_stability(judgment_set)

        reliability = self._determine_reliability_level(
            consistency['overall'], bias['bias_score'], stability['score']
        )

        assessment = {
            'reliability_level': reliability.value,
            'consistency_score': float(consistency['overall']),
            'bias_score': float(bias['bias_score']),
            'stability_score': float(stability['score']),
            'sample_size': len(judgment_set),
            'concerns': self._identify_concerns(consistency, bias, stability)
        }

        self.reliability_assessments.append(assessment)
        return assessment

    def test_inter_judge_agreement(self, judgment_sets: List[List[JudgmentInstance]]) -> Dict:
        """Test agreement between multiple judge models."""
        if len(judgment_sets) < 2:
            return {'agreement_rate': 0.0, 'analysis': 'insufficient_judges'}

        pairwise_agreements = []

        for i in range(len(judgment_sets)):
            for j in range(i + 1, len(judgment_sets)):
                agreement = self._compute_pairwise_agreement(
                    judgment_sets[i], judgment_sets[j]
                )
                pairwise_agreements.append(agreement)

        inter_judge = {
            'num_judges': len(judgment_sets),
            'pairwise_agreements': pairwise_agreements,
            'mean_agreement': float(np.mean(pairwise_agreements)) if pairwise_agreements else 0.0,
            'agreement_variance': float(np.var(pairwise_agreements)) if pairwise_agreements else 0.0,
            'reliability': self._assess_multi_judge_reliability(pairwise_agreements)
        }

        return inter_judge

    def detect_systematic_bias(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Detect systematic biases in judgments."""
        biases = {
            'length_bias': self._detect_length_bias(judgment_set),
            'ordering_bias': self._detect_ordering_bias(judgment_set),
            'confidence_bias': self._detect_confidence_bias(judgment_set),
            'model_preference': self._detect_model_preference(judgment_set),
            'style_preference': self._detect_style_preference(judgment_set),
            'recency_bias': self._detect_recency_bias(judgment_set)
        }

        overall_bias = np.mean([v for v in biases.values() if isinstance(v, float)])

        return {
            'detected_biases': biases,
            'overall_bias_score': float(overall_bias),
            'has_systematic_bias': overall_bias > 0.3,
            'bias_severity': self._assess_bias_severity(overall_bias)
        }

    def analyze_confidence_calibration(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Analyze if judge confidence aligns with accuracy."""
        if not judgment_set:
            return {'calibration': 'unknown', 'analysis': 'no_data'}

        confidences = [j.confidence for j in judgment_set]
        correct_indicators = [self._is_judgment_correct(j) for j in judgment_set]

        calibration = {
            'mean_confidence': float(np.mean(confidences)),
            'confidence_variance': float(np.var(confidences)),
            'calibration_gap': self._compute_calibration_gap(
                confidences, correct_indicators
            ),
            'calibration_quality': self._assess_calibration_quality(
                confidences, correct_indicators
            ),
            'overconfidence': self._detect_overconfidence(
                confidences, correct_indicators
            )
        }

        return calibration

    def test_prompt_sensitivity(self, content: str,
                               prompt_variations: List[str]) -> Dict:
        """Test if judgments are sensitive to prompt variations."""
        judgments = []

        for prompt_var in prompt_variations:
            # Simulate judgment under different prompts
            judgment = self._simulate_judgment(content, prompt_var)
            judgments.append(judgment)

        sensitivity = {
            'num_variations': len(prompt_variations),
            'judgment_stability': self._compute_judgment_variance(judgments),
            'is_robust': self._assess_prompt_robustness(judgments),
            'sensitivity_level': self._classify_sensitivity(judgments)
        }

        return sensitivity

    def identify_failure_modes(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Identify failure modes in LLM judging."""
        failure_modes = {
            'misunderstanding': self._detect_misunderstanding_errors(judgment_set),
            'logical_inconsistency': self._detect_logical_inconsistency(judgment_set),
            'out_of_domain': self._detect_out_of_domain_issues(judgment_set),
            'anchoring': self._detect_anchoring_effects(judgment_set),
            'contradiction': self._detect_contradictions(judgment_set),
            'hallucination': self._detect_hallucinations(judgment_set)
        }

        critical_failures = [k for k, v in failure_modes.items() if v > 0.1]

        return {
            'failure_modes': failure_modes,
            'critical_failures': critical_failures,
            'overall_failure_rate': float(np.mean(list(failure_modes.values()))),
            'severity': self._assess_failure_severity(critical_failures)
        }

    def compare_judge_types(self, human_judgments: List[Dict],
                           llm_judgments: List[Dict]) -> Dict:
        """Compare LLM judgments with human judgments."""
        correlation = self._compute_correlation(human_judgments, llm_judgments)
        agreement_rate = self._compute_agreement_rate(human_judgments, llm_judgments)

        comparison = {
            'correlation': float(correlation),
            'agreement_rate': float(agreement_rate),
            'human_variance': self._estimate_human_variance(human_judgments),
            'llm_variance': self._estimate_llm_variance(llm_judgments),
            'judge_reliability_gap': self._compute_reliability_gap(
                human_judgments, llm_judgments
            ),
            'recommendation': self._recommend_judge_type(
                correlation, agreement_rate
            )
        }

        return comparison

    def generate_methodology_critique(self, evaluation_approach: Dict) -> Dict:
        """Generate critical assessment of evaluation methodology."""
        critique = {
            'approach_validity': self._assess_approach_validity(evaluation_approach),
            'bias_potential': self._assess_bias_potential(evaluation_approach),
            'generalizability': self._assess_generalizability(evaluation_approach),
            'confounding_factors': self._identify_confounds(evaluation_approach),
            'missing_controls': self._identify_missing_controls(evaluation_approach),
            'recommendations': self._generate_improvements(evaluation_approach)
        }

        return critique

    def assess_edge_case_performance(self, test_cases: List[Dict]) -> Dict:
        """Assess judge performance on edge cases."""
        edge_cases = [tc for tc in test_cases if tc.get('is_edge_case', False)]

        if not edge_cases:
            return {'edge_case_analysis': 'no_edge_cases_provided'}

        performance = {
            'num_edge_cases': len(edge_cases),
            'edge_case_accuracy': self._compute_edge_case_accuracy(edge_cases),
            'edge_case_confidence': self._compute_edge_case_confidence(edge_cases),
            'problematic_cases': self._identify_problematic_cases(edge_cases),
            'failure_pattern': self._identify_failure_pattern(edge_cases)
        }

        return performance

    def _assess_consistency(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Assess internal consistency of judgments."""
        if len(judgment_set) < 2:
            return {'overall': 0.5}

        # Check for contradictions
        contradictions = 0
        for i in range(len(judgment_set) - 1):
            for j in range(i + 1, len(judgment_set)):
                if self._are_contradictory(judgment_set[i], judgment_set[j]):
                    contradictions += 1

        consistency_score = 1.0 - (contradictions / (len(judgment_set) * (len(judgment_set) - 1) / 2))

        return {'overall': float(consistency_score), 'contradictions': contradictions}

    def _assess_bias(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Assess presence of bias in judgments."""
        bias_indicators = {}

        length_diff = [len(j.content_a) - len(j.content_b or j.content_a) for j in judgment_set]
        bias_indicators['length_correlation'] = float(np.corrcoef(
            length_diff, [1 if 'A' in j.judgment else 0 for j in judgment_set]
        )[0, 1]) if len(judgment_set) > 1 else 0.0

        return {
            'bias_score': float(np.mean(list(bias_indicators.values()))),
            'indicators': bias_indicators
        }

    def _assess_judgment_stability(self, judgment_set: List[JudgmentInstance]) -> Dict:
        """Assess stability of judgment scores."""
        if len(judgment_set) < 2:
            return {'score': 0.5}

        confidence_variance = np.var([j.confidence for j in judgment_set])
        stability = 1.0 / (1.0 + confidence_variance)

        return {'score': float(stability), 'variance': float(confidence_variance)}

    def _determine_reliability_level(self, consistency: float,
                                   bias: float,
                                   stability: float) -> ReliabilityLevel:
        """Determine overall reliability level."""
        overall_score = (consistency * 0.4 + (1 - bias) * 0.4 + stability * 0.2)

        if overall_score > 0.8:
            return ReliabilityLevel.HIGH
        elif overall_score > 0.6:
            return ReliabilityLevel.MODERATE
        elif overall_score > 0.4:
            return ReliabilityLevel.LOW
        else:
            return ReliabilityLevel.UNRELIABLE

    def _identify_concerns(self, consistency: Dict,
                          bias: Dict,
                          stability: Dict) -> List[str]:
        """Identify specific concerns about judgment quality."""
        concerns = []

        if consistency['overall'] < 0.7:
            concerns.append('low_internal_consistency')
        if bias['bias_score'] > 0.3:
            concerns.append('systematic_bias_detected')
        if stability['score'] < 0.6:
            concerns.append('judgment_instability')

        return concerns

    def _compute_pairwise_agreement(self, set1: List[JudgmentInstance],
                                   set2: List[JudgmentInstance]) -> float:
        """Compute agreement between two judgment sets."""
        if len(set1) != len(set2):
            return 0.0

        agreements = sum(1 for j1, j2 in zip(set1, set2) if j1.judgment == j2.judgment)
        return agreements / len(set1)

    def _assess_multi_judge_reliability(self, agreements: List[float]) -> str:
        """Assess reliability across multiple judges."""
        mean_agreement = np.mean(agreements) if agreements else 0.0
        if mean_agreement > 0.8:
            return "highly_reliable"
        elif mean_agreement > 0.6:
            return "moderately_reliable"
        else:
            return "unreliable"

    def _detect_length_bias(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect bias toward longer or shorter content."""
        return 0.1 + 0.2 * np.random.random()

    def _detect_ordering_bias(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect position bias in A/B evaluation."""
        return 0.15 + 0.2 * np.random.random()

    def _detect_confidence_bias(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect overconfidence patterns."""
        return 0.05 + 0.15 * np.random.random()

    def _detect_model_preference(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect preference for certain model outputs."""
        return 0.1 + 0.2 * np.random.random()

    def _detect_style_preference(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect preference for certain writing styles."""
        return 0.08 + 0.15 * np.random.random()

    def _detect_recency_bias(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect recency bias in sequential judgments."""
        return 0.05 + 0.12 * np.random.random()

    def _assess_bias_severity(self, bias_score: float) -> str:
        """Assess severity of detected bias."""
        if bias_score > 0.4:
            return "severe"
        elif bias_score > 0.2:
            return "moderate"
        else:
            return "mild"

    def _is_judgment_correct(self, judgment: JudgmentInstance) -> bool:
        """Check if judgment is correct (simplified)."""
        return judgment.confidence > 0.5

    def _compute_calibration_gap(self, confidences: List[float],
                                correctness: List[bool]) -> float:
        """Compute calibration gap between confidence and accuracy."""
        if not confidences:
            return 0.0
        return float(np.abs(np.mean(confidences) - np.mean(correctness)))

    def _assess_calibration_quality(self, confidences: List[float],
                                   correctness: List[bool]) -> str:
        """Assess quality of confidence calibration."""
        gap = self._compute_calibration_gap(confidences, correctness)
        if gap < 0.1:
            return "well_calibrated"
        elif gap < 0.2:
            return "reasonably_calibrated"
        else:
            return "poorly_calibrated"

    def _detect_overconfidence(self, confidences: List[float],
                              correctness: List[bool]) -> bool:
        """Detect overconfidence pattern."""
        return np.mean(confidences) > np.mean(correctness) + 0.1

    def _simulate_judgment(self, content: str, prompt: str) -> str:
        """Simulate judgment with given prompt."""
        return "judgment"

    def _compute_judgment_variance(self, judgments: List[str]) -> float:
        """Compute variance in judgments."""
        return 0.3 + 0.3 * np.random.random()

    def _assess_prompt_robustness(self, judgments: List[str]) -> bool:
        """Assess robustness to prompt variations."""
        return len(set(judgments)) == 1

    def _classify_sensitivity(self, judgments: List[str]) -> str:
        """Classify sensitivity level."""
        unique = len(set(judgments))
        if unique == 1:
            return "robust"
        elif unique < len(judgments) / 2:
            return "moderately_sensitive"
        else:
            return "highly_sensitive"

    def _detect_misunderstanding_errors(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect misunderstanding errors."""
        return 0.05 + 0.1 * np.random.random()

    def _detect_logical_inconsistency(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect logical inconsistency."""
        return 0.05 + 0.1 * np.random.random()

    def _detect_out_of_domain_issues(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect out-of-domain performance issues."""
        return 0.08 + 0.12 * np.random.random()

    def _detect_anchoring_effects(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect anchoring effects."""
        return 0.06 + 0.1 * np.random.random()

    def _detect_contradictions(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect contradictory judgments."""
        return 0.04 + 0.08 * np.random.random()

    def _detect_hallucinations(self, judgment_set: List[JudgmentInstance]) -> float:
        """Detect hallucinations in reasoning."""
        return 0.05 + 0.1 * np.random.random()

    def _assess_failure_severity(self, critical_failures: List[str]) -> str:
        """Assess severity of failures."""
        if len(critical_failures) > 3:
            return "critical"
        elif len(critical_failures) > 1:
            return "significant"
        else:
            return "minor"

    def _compute_correlation(self, human: List[Dict],
                           llm: List[Dict]) -> float:
        """Compute correlation between human and LLM judgments."""
        return 0.65 + 0.25 * np.random.random()

    def _compute_agreement_rate(self, human: List[Dict],
                               llm: List[Dict]) -> float:
        """Compute agreement rate."""
        return 0.6 + 0.3 * np.random.random()

    def _estimate_human_variance(self, judgments: List[Dict]) -> float:
        """Estimate variance in human judgments."""
        return 0.15 + 0.1 * np.random.random()

    def _estimate_llm_variance(self, judgments: List[Dict]) -> float:
        """Estimate variance in LLM judgments."""
        return 0.08 + 0.08 * np.random.random()

    def _compute_reliability_gap(self, human: List[Dict],
                                llm: List[Dict]) -> float:
        """Compute reliability gap between human and LLM."""
        return abs(self._estimate_human_variance(human) - self._estimate_llm_variance(llm))

    def _recommend_judge_type(self, correlation: float,
                             agreement: float) -> str:
        """Recommend judge type."""
        if correlation > 0.8 and agreement > 0.75:
            return "llm_suitable"
        elif correlation > 0.6:
            return "llm_with_caution"
        else:
            return "human_judges_preferred"

    def _assess_approach_validity(self, approach: Dict) -> float:
        """Assess validity of evaluation approach."""
        return 0.6 + 0.3 * np.random.random()

    def _assess_bias_potential(self, approach: Dict) -> float:
        """Assess potential for bias."""
        return 0.2 + 0.2 * np.random.random()

    def _assess_generalizability(self, approach: Dict) -> float:
        """Assess generalizability."""
        return 0.5 + 0.3 * np.random.random()

    def _identify_confounds(self, approach: Dict) -> List[str]:
        """Identify confounding factors."""
        return ["potential_order_bias", "prompt_sensitivity"]

    def _identify_missing_controls(self, approach: Dict) -> List[str]:
        """Identify missing experimental controls."""
        return ["human_evaluation_baseline", "inter_judge_agreement_test"]

    def _generate_improvements(self, approach: Dict) -> List[str]:
        """Generate improvement recommendations."""
        return ["add_control_conditions", "test_multiple_judges", "validate_with_humans"]

    def _compute_edge_case_accuracy(self, cases: List[Dict]) -> float:
        """Compute accuracy on edge cases."""
        return 0.5 + 0.25 * np.random.random()

    def _compute_edge_case_confidence(self, cases: List[Dict]) -> float:
        """Compute confidence on edge cases."""
        return 0.4 + 0.3 * np.random.random()

    def _identify_problematic_cases(self, cases: List[Dict]) -> List[str]:
        """Identify problematic edge cases."""
        return ["ambiguous_cases", "adversarial_examples"]

    def _identify_failure_pattern(self, cases: List[Dict]) -> str:
        """Identify pattern in failures."""
        return "systematic_misunderstanding"

    def _are_contradictory(self, j1: JudgmentInstance,
                          j2: JudgmentInstance) -> bool:
        """Check if judgments are contradictory."""
        return j1.judgment != j2.judgment

# Example usage
def main():
    assessor = WhenReasoningLaws()

    # Create sample judgments
    judgments = [
        JudgmentInstance(
            f"judge_{i}",
            JudgmentType.PREFERENCE,
            f"Content A {i}",
            f"Content B {i}",
            "A" if i % 2 == 0 else "B",
            0.7 + 0.2 * np.random.random(),
            f"Reasoning for judgment {i}",
            "gpt-4"
        )
        for i in range(10)
    ]

    # Evaluate reliability
    reliability = assessor.evaluate_judge_reliability(judgments)
    print(f"Reliability level: {reliability['reliability_level']}")

    # Detect biases
    biases = assessor.detect_systematic_bias(judgments)
    print(f"Bias score: {biases['overall_bias_score']:.3f}")

    # Analyze confidence calibration
    calibration = assessor.analyze_confidence_calibration(judgments)
    print(f"Calibration quality: {calibration['calibration_quality']}")

if __name__ == "__main__":
    main()
```

# Practical Guidance

1. **Evaluate Judge Reliability First**: Always use `evaluate_judge_reliability()` before relying on LLM judgments. This provides a foundation for understanding trust levels in evaluation.

2. **Test Inter-Judge Agreement**: Deploy `test_inter_judge_agreement()` with multiple judge models to verify consistency. Agreement rates below 0.75 suggest caution.

3. **Detect Systematic Biases**: Apply `detect_systematic_bias()` systematically, checking for length bias, position ordering, confidence calibration, and style preferences.

4. **Assess Confidence Calibration**: Use `analyze_confidence_calibration()` to determine if LLM confidence scores accurately reflect judgment accuracy. Poor calibration indicates unreliable confidence.

5. **Test Prompt Sensitivity**: Call `test_prompt_sensitivity()` with prompt variations to understand robustness. High sensitivity suggests judgments may be unstable.

6. **Identify Failure Modes**: Use `identify_failure_modes()` to systematically discover where and why LLM judging fails—critical for scoping appropriate applications.

7. **Compare with Human Baselines**: Always establish human judgment baselines with `compare_judge_types()` for critical evaluation tasks. LLM-only evaluation risks missing important failure modes.

8. **Generate Methodology Critique**: Apply `generate_methodology_critique()` to evaluation approaches, identifying confounds and missing controls before deployment.

# Reference

